- **CLI Commands**:
  - `npm install sequelize --save`
  - `npm install pg pg-hstore --save` for PostgreSQL

- **Latest Versions**:
  - Sequelize: v6.x
  - Node.js: v14.x, v16.x, v18.x

- **Key Config Options**:
  - `database`: Database name
  - `username`: Database username
  - `password`: Database password
  - `host`: Database host
  - `dialect`: Database dialect (e.g., 'postgres', 'mysql')

- **Example Code Snippet for CRUD Operations**:

```javascript
const { Sequelize, DataTypes } = require('sequelize');

// Initialize Sequelize with your database configuration
const sequelize = new Sequelize('database', 'username', 'password', {
  host: 'localhost',
  dialect: 'postgres'
});

// Define a model
const User = sequelize.define('User', {
  firstName: DataTypes.STRING,
  lastName: DataTypes.STRING
}, { tableName: 'users' });

// Create a new user
async function createUser() {
  const newUser = await User.create({
    firstName: 'John',
    lastName: 'Doe'
  });
  console.log(newUser.toJSON());
}

// Read all users
async function findAllUsers() {
  const users = await User.findAll();
  console.log(users.map(user => user.toJSON()));
}

// Update a user
async function updateUser() {
  const [updated] = await User.update({ lastName: 'Smith' }, { where: { firstName: 'John' } });
  console.log(`${updated} record(s) updated`);
}

// Delete a user
async function deleteUser() {
  const deleted = await User.destroy({ where: { firstName: 'John', lastName: 'Smith' } });
  console.log(`${deleted} record(s) deleted`);
}

// Execute functions
createUser();
findAllUsers();
updateUser();
deleteUser();
```

This code snippet demonstrates how to perform basic CRUD operations using Sequelize in a Node.js application.
